/* ==========================================================================
   PL/SW IDE -- App styles (Catppuccin Mocha theme)
   ========================================================================== */

/* --- 3-column wizard layout --- */
.plsw-wizard-layout {
    display: grid;
    grid-template-columns: 120px 150px 1fr;
    height: 100%;
    overflow: hidden;
}

/* Column 1: Sidebar with buttons */
.wizard-sidebar {
    display: flex;
    flex-direction: column;
    padding: 8px;
    background: var(--mantle);
    border-right: 1px solid var(--surface1);
    gap: 8px;
}

.sidebar-section {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.sidebar-section-label {
    font-size: 0.7em;
    color: var(--overlay0);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    padding: 0 4px;
}

.sidebar-btn {
    width: 100%;
    padding: 7px 8px;
    background: var(--surface0);
    color: var(--blue);
    border: 1px solid var(--surface1);
    border-radius: 4px;
    cursor: pointer;
    font-family: var(--mono);
    font-weight: bold;
    font-size: 0.75em;
    transition: all 0.15s;
}

.sidebar-btn:hover {
    background: var(--surface1);
    border-color: var(--blue);
}

.sidebar-select {
    width: 100%;
    padding: 6px 8px;
    background: var(--surface0);
    color: var(--text);
    border: 1px solid var(--surface1);
    border-radius: 4px;
    font-family: var(--mono);
    font-size: 0.75em;
    cursor: pointer;
}

.sidebar-select:focus {
    outline: none;
    border-color: var(--blue);
}

.sidebar-spacer {
    flex: 1;
}

.sidebar-link {
    display: block;
    padding: 7px 8px;
    color: var(--overlay2);
    text-decoration: none;
    font-size: 0.75em;
    font-weight: bold;
    border-radius: 4px;
    transition: color 0.15s;
}

.sidebar-link:hover {
    color: var(--blue);
}

.sidebar-link .ext-icon {
    font-size: 0.8em;
}

